import{_ as p,c as t,o as e,d as a}from"./plugin-vue_export-helper.23b45acd.js";const u='{"title":"\u0422\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043C\u0438\u0440\u0430 \u0447\u0435\u0440\u0435\u0437 36 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432","description":"","frontmatter":{"title":"\u0422\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043C\u0438\u0440\u0430 \u0447\u0435\u0440\u0435\u0437 36 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432","tags":"scheme"},"relativePath":"schemes/creation/index.md","lastUpdated":1625171795307}',o={},s=a('<div class="stanza"><p>\u041F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043E \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0438 \u043C\u0438\u0440\u0430 \u043A\u0430\u043A \u043E \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438 <strong>36 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F (36 \u0442\u0430\u0442\u0442\u0432)</strong> \u043F\u0440\u0438\u0441\u0443\u0449\u0435 \u0448\u0438\u0432\u0430\u0438\u0442\u0441\u043A\u0438\u043C (\u0448\u0430\u0439\u0432\u0430) \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0438\u044F\u043C, \u0432 \u0442\u043E\u043C \u0447\u0438\u0441\u043B\u0435 \u0438 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0438\u0438 \u0432\u0438\u0440\u0430\u0448\u0430\u0439\u0432\u0430.</p><p>\u0414\u043E \u043D\u0430\u0447\u0430\u043B\u0430 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043B \u043B\u0438\u0448\u044C \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u0441\u043E \u0441\u0432\u043E\u0435\u0439 \u041F\u0430\u0440\u0430\u0448\u0430\u043A\u0442\u0438 (\u0432\u044B\u0441\u0448\u0435\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439, \u0441\u0438\u043B\u043E\u0439). \u0422\u043E\u0433\u0434\u0430 \u043D\u0435 \u0431\u044B\u043B\u043E \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u0434\u0435\u043B\u0435\u043D\u0438\u044F \u043D\u0430 \u0442\u043E\u043D\u043A\u043E\u0435, \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435, \u0434\u0443\u0445, \u043C\u0430\u0442\u0435\u0440\u0438\u044E \u0438 \u0442.\u043F.</p><blockquote><p>\xAB\u041A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0431\u044B\u043B\u043E \u043D\u0438 \u0434\u043D\u044F, \u043D\u0438 \u043D\u043E\u0447\u0438, \u043D\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E, \u043D\u0438 \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0433\u043E, \u0442\u043E\u0433\u0434\u0430 \u0431\u044B\u043B \u043B\u0438\u0448\u044C \u0428\u0438\u0432\u0430 \u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u0428\u0438\u0432\u0430. \u041E\u043D \u0431\u044B\u043B \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u043C. \u041E\u043D \u0431\u044B\u043B \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0446\u0435\u043B\u044C\u044E \u0438\u0441\u043A\u0430\u0442\u0435\u043B\u0435\u0439 \u0411\u043E\u0433\u0430. \u0418\u0437 \u043D\u0435\u0433\u043E \u0432\u043E\u0437\u043D\u0438\u043A \u0434\u0440\u0435\u0432\u043D\u0438\u0439 \u0440\u0430\u0437\u0443\u043C.\xBB <strong>(\u0428\u0432\u0435\u0442\u0430\u0448\u0432\u0430\u0442\u0430\u0440\u0430 \u0423\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430, 4.18)</strong></p></blockquote><p>\u042D\u0442\u043E\u0442 \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D \xAB\u0437\u0430\u0445\u043E\u0442\u0435\u043B \u0441\u0442\u0430\u0442\u044C \u043C\u043D\u043E\u0433\u0438\u043C\u0438\xBB (\u0422\u0430\u0438\u0442\u0438\u0440\u0438\u044F \u0423\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430, 2.6). \u0422\u0430\u043A \u043E\u043D \u0441\u0442\u0430\u043B \u0433\u043E\u0442\u043E\u0432 \u043A \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044E. \u0410 \u0435\u0433\u043E \u0412\u0438\u043C\u0430\u0440\u0448\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u043C\u044B\u0441\u043B\u0438, \u0441\u0438\u043B\u0430 \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u044F) \u043F\u0440\u0438\u043D\u044F\u043B\u0430 \u043E\u0431\u0440\u0430\u0437 \u043C\u0438\u0440\u0430, \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u043F\u0440\u0435\u0434\u0441\u0442\u043E\u044F\u043B\u043E \u0431\u044B\u0442\u044C \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u043C. \u0417\u0430\u0442\u0435\u043C \u0438\u0437 \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 \u043F\u043E\u044F\u0432\u0438\u043B\u0430\u0441\u044C \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u044F), \u0430 \u0438\u0437 \u043D\u0435\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u043B\u0438 \u0414\u0436\u043D\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0437\u043D\u0430\u043D\u0438\u044F) \u0438 \u041A\u0440\u0438\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F). \u0414\u0436\u043D\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0437\u043D\u0430\u043D\u0438\u044F) \u0431\u044B\u043B\u0430 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u044B \u0436\u0435\u043B\u0430\u043D\u0438\u044F). \u0410 \u041A\u0440\u0438\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F) \u0431\u044B\u043B\u0430 \u0432\u043D\u0435\u0448\u043D\u0438\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u044B \u0436\u0435\u043B\u0430\u043D\u0438\u044F).</p><p>\u0417\u0430\u0442\u0435\u043C \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u0432\u043E\u0448\u0435\u043B \u0432 \u0414\u0436\u043D\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0443 \u0437\u043D\u0430\u043D\u0438\u044F), \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u0432 \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438, \u0438 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B \u0438\u0434\u0435\u044E \xAB\u042F \u0432\u0441\u0435\u0437\u043D\u0430\u044E\u0449\u0438\u0439\xBB. \u0422\u0430\u043A \u043E\u043D \u043F\u0440\u0438\u043D\u044F\u043B \u0444\u043E\u0440\u043C\u0443 \u0428\u0438\u0432\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (1). \u042D\u0442\u043E\u0442 \u044D\u043B\u0435\u043C\u0435\u043D\u0442 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u0441\u0442\u0430\u043B \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0431\u0443\u0434\u0443\u0449\u0435\u0433\u043E \u043C\u0438\u0440\u0430, \u043A\u0430\u043A \u043F\u0430\u0443\u043A \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A \u0441\u0432\u043E\u0435\u0439 \u043F\u0430\u0443\u0442\u0438\u043D\u0435.</p><p>\u041A\u043E\u0433\u0434\u0430 \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u0432\u043E\u0448\u0435\u043B \u0432 \u041A\u0440\u0438\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0443 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043D\u0435\u0448\u043D\u0435\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u043E\u0439 \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u044B \u0436\u0435\u043B\u0430\u043D\u0438\u044F), \u0438 \u043F\u043E\u044F\u0432\u0438\u043B\u0430\u0441\u044C \u0438\u0434\u0435\u044F \xAB\u042F \u0432\u0441\u0435\u043C\u043E\u0433\u0443\u0449\u0438\u0439\xBB, \u043E\u043D \u0441\u0442\u0430\u043B \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u043E\u0439 (2). \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u0432 \u0444\u043E\u0440\u043C\u0435 \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u044B \u0441\u0442\u0430\u043B \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F \u043C\u0438\u0440\u0430, \u043A\u0430\u043A \u043F\u0430\u0443\u043A, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043E\u0441\u043E\u0431\u043E\u043C\u0443 \u0432\u0435\u0449\u0435\u0441\u0442\u0432\u0443, \u0432\u044B\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u043C\u043E\u043C\u0443 \u0435\u0433\u043E \u0442\u0435\u043B\u043E\u043C, \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u044C \u0441\u0430\u043C\u0443 \u0442\u043A\u0430\u043D\u044C \u043F\u0430\u0443\u0442\u0438\u043D\u044B. \u0422\u0430\u043A \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D \u0441\u0442\u0430\u043B \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u043C \u0438 \u043C\u0430\u0442\u0435\u0440\u0438\u0435\u0439, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043E\u0437\u0434\u0430\u043D \u043C\u0438\u0440. \u041E\u0431 \u044D\u0442\u043E\u043C \u0436\u0435 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u0432 \u041C\u0443\u043D\u0434\u0430\u043A\u0430 \u0423\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0435 (1.1.7):</p><p>\xAB\u041A\u0430\u043A \u043F\u0430\u0443\u043A \u0441\u043E\u0437\u0434\u0430\u0435\u0442 \u043F\u0430\u0443\u0442\u0438\u043D\u0443 \u0438 \u0441\u043E\u0431\u0438\u0440\u0430\u0435\u0442 \u0435\u0435 \u043E\u0431\u0440\u0430\u0442\u043D\u043E, \u043A\u0430\u043A \u0442\u0440\u0430\u0432\u044B \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0438\u0437 \u0437\u0435\u043C\u043B\u0438, \u0438 \u043A\u0430\u043A \u0432\u043E\u043B\u043E\u0441\u044B \u0440\u0430\u0441\u0442\u0443\u0442 \u043D\u0430 \u0433\u043E\u043B\u043E\u0432\u0435 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0442\u0430\u043A \u0436\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u043E\u044F\u0432\u0438\u043B\u0430\u0441\u044C \u0438\u0437 \u041D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u043E\u0433\u043E.\xBB \u0417\u0430\u0442\u0435\u043C \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u0432\u043E\u0448\u043B\u0430 \u0432 \u0414\u0436\u043D\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438, \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438, \u0438 \u043D\u0430\u0431\u0443\u0445\u043B\u0430, \u043A\u0430\u043A \u0433\u043E\u0440\u043E\u0445, \u0437\u0430\u043C\u043E\u0447\u0435\u043D\u043D\u044B\u0439 \u0432 \u0432\u043E\u0434\u0435. \u0412 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435, \u0441 \u0438\u0434\u0435\u0435\u0439 \xAB\u042D\u0442\u043E \u044F\xBB \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0437\u0430\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u043C\u0438\u0440\u0430, \u043E\u043D\u0430 \u0441\u0442\u0430\u043B\u0430 \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430-\u0442\u0430\u0442\u0442\u0432\u043E\u0439 (3).</p><p>\u0418 \u0441\u043D\u043E\u0432\u0430 \u0442\u0430 \u0436\u0435 \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u0432\u043E\u0448\u043B\u0430 \u0432 \u041A\u0440\u0438\u0439\u044F-\u0448\u0430\u043A\u0442\u0438, \u0432\u043D\u0435\u0448\u043D\u0435\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438, \u0438 \u043F\u0440\u043E\u0440\u043E\u0441\u043B\u0430, \u043A\u0430\u043A \u0445\u043E\u0440\u043E\u0448\u0435\u0435 \u0437\u0435\u0440\u043D\u043E \u0432 \u0445\u043E\u0440\u043E\u0448\u0435\u0439 \u043F\u043E\u0447\u0432\u0435. \u0422\u0430\u043A, \u0441 \u0438\u0434\u0435\u0435\u0439 \xAB\u042D\u0442\u043E \u044F\xBB \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u043E\u044F\u0432\u0438\u0432\u0448\u0435\u0433\u043E\u0441\u044F \u043C\u0438\u0440\u0430, \u043E\u043D\u0430 \u043F\u0440\u0438\u043D\u044F\u043B\u0430 \u0444\u043E\u0440\u043C\u0443 \u0418\u0448\u0432\u0430\u0440\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (4).</p><p>\u041A\u043E\u0433\u0434\u0430 \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B\u0430 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0438\u0434\u0435\u043D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \xAB\u042F\xBB \u0438 \xAB\u044D\u0442\u043E\xBB \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043C\u0438\u0440\u0430, \u043E\u043D\u0430 \u0441\u0442\u0430\u043B\u0430 \u0428\u0443\u0434\u0434\u0445\u0430\u0432\u0438\u0434\u044C\u044F-\u0442\u0430\u0442\u0442\u0432\u043E\u0439 (5) (\u0447\u0438\u0441\u0442\u044B\u043C \u0437\u043D\u0430\u043D\u0438\u0435\u043C). \u0417\u0434\u0435\u0441\u044C \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043E \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u0447\u043D\u043E \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0443 \u043E\u043A\u0435\u0430\u043D\u0430 \u0438 \u0435\u0433\u043E \u0432\u043E\u043B\u043D.</p><p>\u0412\u044B\u0448\u0435\u0440\u0435\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0435 \u043F\u044F\u0442\u044C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \xAB\u0448\u0443\u0434\u0434\u0445\u0430 \u0442\u0430\u0442\u0442\u0432\u0430\xBB (\u0447\u0438\u0441\u0442\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B).</p><p>\u041F\u044F\u0442\u044B\u0439 \u044D\u043B\u0435\u043C\u0435\u043D\u0442 \u2013 \u0428\u0443\u0434\u0434\u0445\u0430\u0432\u0438\u0434\u044C\u044F-\u0442\u0430\u0442\u0442\u0432\u0430 \u0441\u0442\u0430\u043B \u041C\u0430\u0439\u044F-\u0442\u0430\u0442\u0442\u0432\u043E\u0439 (6) (\u0438\u043B\u043B\u044E\u0437\u0438\u0435\u0439). \u042D\u0442\u043E \u043F\u0440\u043E\u0438\u0437\u043E\u0448\u043B\u043E \u0442\u043E\u0433\u0434\u0430, \u043A\u043E\u0433\u0434\u0430 \u0441\u0442\u0430\u043B\u043E \u043F\u0440\u0435\u043E\u0431\u043B\u0430\u0434\u0430\u0442\u044C \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 \u0441\u0440\u0435\u0434\u0438 \u0442\u043E\u043D\u043A\u0438\u0445 \u0444\u043E\u0440\u043C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u0432 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043A\u0440\u044B\u043B\u0430\u0441\u044C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0431\u0443\u0434\u0443\u0449\u0435\u0433\u043E \u043C\u0438\u0440\u0430. \u042D\u0442\u043E \u0431\u044B\u043B\u043E \u043A\u0430\u043A \u043F\u0440\u043E\u0437\u0440\u0430\u0447\u043D\u0430\u044F \u0436\u0438\u0434\u043A\u043E\u0441\u0442\u044C \u0432 \u044F\u0439\u0446\u0435 \u043F\u0430\u0432\u043B\u0438\u043D\u0430 \u2013 \u0432 \u043D\u0435\u0439 \u0432 \u0442\u043E\u043D\u043A\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 \u0443\u0436\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u043C\u0435\u0436\u0434\u0443 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u0431\u0443\u0434\u0443\u0449\u0438\u0445 \u043B\u0430\u043F, \u043A\u0440\u044B\u043B\u044C\u0435, \u043C\u043D\u043E\u0433\u043E\u0446\u0432\u0435\u0442\u0438\u044F \u043F\u0435\u0440\u044C\u0435\u0432 \u0438 \u0442.\u0434.</p><p>\u041A\u0430\u043A \u0438\u0441\u043A\u0440\u044B \u043F\u043B\u0430\u043C\u0435\u043D\u0438 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442 \u043E\u0442 \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u0430 \u0445\u0432\u043E\u0440\u043E\u0441\u0442\u0430 \u0438 \u043E\u0433\u043D\u044F, \u0442\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C \u0447\u0430\u0441\u0442\u0438\u0446\u0430 \u0428\u0438\u0432\u044B \u043F\u043E\u044F\u0432\u0438\u043B\u0430\u0441\u044C \u043E\u0442 \u043A\u043E\u043D\u0442\u0430\u043A\u0442\u0430 \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u044B \u0436\u0435\u043B\u0430\u043D\u0438\u044F) \u0438 \u0428\u0438\u0432\u044B. \u042D\u0442\u0430 \u0447\u0430\u0441\u0442\u0438\u0446\u0430 \u0428\u0438\u0432\u044B \u0432\u043E\u0448\u043B\u0430 \u0432 \u041C\u0430\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 \u0438 \u0441\u0442\u0430\u043B\u0430 \u041F\u0443\u0440\u0443\u0448\u0430-\u0442\u0430\u0442\u0442\u0432\u043E\u0439 (7). \u042D\u0442\u043E \u0431\u044B\u043B\u0430 \u0434\u0436\u0438\u0432\u0430 (\u0436\u0438\u0432\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E), \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0434\u0443\u043C\u0430\u043B\u0430 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F\u043C\u0438 \xAB\u042F \u0441\u0447\u0430\u0441\u0442\u043B\u0438\u0432\u0430\xBB \u0438 \xAB\u042F \u043D\u0435\u0441\u0447\u0430\u0441\u0442\u043B\u0438\u0432\u0430\xBB. \u042D\u0442\u0438 \u0438\u0434\u0435\u0438 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u043B\u0438 \u0438\u0437-\u0437\u0430 \u043D\u0435\u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0430\u0442\u044C \u0447\u0442\u043E \u0435\u0441\u0442\u044C \u042F \u0438 \u0447\u0442\u043E \u043C\u043D\u043E\u0439 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F.</p><p>\u041F\u0443\u0440\u0443\u0448\u0430-\u0442\u0430\u0442\u0432\u0430 \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0430 \u043F\u044F\u0442\u044C\u044E \u0441\u043B\u043E\u044F\u043C\u0438 \u0431\u0440\u043E\u043D\u0438 (\u043A\u0430\u043D\u0447\u0443\u043A\u0430), \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044E\u0442 \u0435\u0435 \u0432 \u044D\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438: \u041A\u0430\u043B\u0410, \u0410\u0432\u0438\u0434\u044C\u044F, \u0420\u0430\u0433\u0430, \u041A\u0410\u043B\u0430 \u0438 \u041D\u0438\u044F\u0442\u0438.</p><p>\u041A\u0430\u043B\u0410-\u0442\u0430\u0442\u0442\u0432\u0430 (8) (\u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u044C) \u0432\u044B\u0440\u0430\u0436\u0430\u0435\u0442\u0441\u044F \u0432 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438 \u043A \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C \u0438\u0437-\u0437\u0430 \u0441\u0432\u044F\u0437\u0438 \u041F\u0443\u0440\u0443\u0448\u0438 \u0441 \u041C\u0430\u0439\u0435\u0439 (\u0438\u043B\u043B\u044E\u0437\u0438\u0435\u0439) \u0438 \u0435\u0433\u043E \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u043E\u0442 \u0428\u0438\u0432\u044B, \u043F\u0440\u0438\u0432\u043E\u0434\u044F\u0449\u0435\u0439 \u043A \u0443\u0442\u0440\u0430\u0442\u0435 \u0432\u0435\u043B\u0438\u0447\u0438\u044F.</p><p>\u0410\u0432\u0438\u0434\u044C\u044F-\u0442\u0430\u0442\u0442\u0432\u0430 (9) (\u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435) \u044D\u0442\u043E \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438 \u043A \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044E \u2013 \u043E\u0442 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F \u0434\u043E \u0447\u0430\u0441\u0442\u0438\u0447\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E \u0442\u043E\u0439 \u0436\u0435 \u043F\u0440\u0438\u0447\u0438\u043D\u0435.</p><p>\u0420\u0430\u0433\u0430-\u0442\u0430\u0442\u0442\u0432\u0430 (10) (\u0441\u0438\u043C\u043F\u0430\u0442\u0438\u044F, \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u0435) \u2013 \u044D\u0442\u043E \u043F\u0440\u0438\u043D\u0446\u0438\u043F \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0442\u044B, \u043D\u0435\u0437\u0430\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430. \u042D\u0442\u043E \u0447\u0443\u0432\u0441\u0442\u0432\u043E \u043D\u0435\u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0442\u043E\u043B\u043A\u0430\u0435\u0442 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0438\u0441\u043A\u0430\u0442\u044C \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0432 \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u043C \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438. \u041E\u0442 \u044D\u0442\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0432\u0441\u0435 \u0431\u043E\u043B\u044C\u0448\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0435 \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D (\u0441\u0430\u043D\u0441\u043A\u0440. \xAB\u0440\u0430\u0433\u0430\xBB) \u043A \u0432\u043D\u0435\u0448\u043D\u0438\u043C \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C \u2013 \u0442\u0430\u043A\u0438\u043C \u043A\u0430\u043A \u0436\u0435\u043D\u0449\u0438\u043D\u044B, \u0435\u0434\u0430, \u0430\u0440\u043E\u043C\u0430\u0442\u044B \u0438 \u0442.\u0434.</p><p>\u041A\u0410\u043B\u0430-\u0442\u0430\u0442\u0442\u0432\u0430 (11) \u2013 \u044D\u0442\u043E \u043F\u0440\u0438\u043D\u0446\u0438\u043F \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u043F\u0440\u0438\u043D\u0446\u0438\u043F \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043F\u0440\u043E\u0448\u043B\u043E\u0433\u043E, \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438 \u0431\u0443\u0434\u0443\u0449\u0435\u0433\u043E, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u0438.</p><p>\u041D\u0438\u044F\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 (12) \u2013 \u044D\u0442\u043E \u043F\u0440\u0438\u043D\u0446\u0438\u043F \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0438\u0437-\u0437\u0430 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0432\u0435\u0437\u0434\u0435\u0441\u0443\u0449\u0435\u0441\u0442\u0438. \u042D\u0442\u0438 \u043F\u044F\u0442\u044C \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 \u0441\u0442\u0430\u0432\u044F\u0442 \u041F\u0443\u0440\u0443\u0448\u0443 \u0432 \u0443\u0441\u043B\u043E\u0432\u0438\u044F, \u0447\u0442\u043E \u043E\u043D \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0442\u0435\u043C \u0438\u043B\u0438 \u0438\u043D\u044B\u043C.</p><p>\u0417\u0430\u0442\u0435\u043C \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0436\u0435\u043B\u0430\u043D\u0438\u044F), \u0433\u043E\u0442\u043E\u0432\u0430\u044F \u043A \u0441\u043E\u0437\u0438\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438, \u043E\u0442\u0440\u0430\u0437\u0438\u043B\u0430\u0441\u044C \u0432 \u041C\u0430\u0439\u044F-\u0442\u0430\u0442\u0442\u0432\u0435 (\u0438\u043B\u043B\u044E\u0437\u0438\u0438), \u0441\u043E\u0437\u0434\u0430\u044E\u0449\u0435\u0439 \u0447\u0443\u0432\u0441\u0442\u0432\u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u0432\u0440\u043E\u0434\u0435 \xAB\u0437\u043D\u0430\u043D\u0438\u0435 \u044D\u0442\u043E \u043D\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F \u2013 \u044D\u0442\u043E \u043D\u0435 \u0437\u043D\u0430\u043D\u0438\u0435\xBB. \u0422\u0430\u043A \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B\u0430 \u0444\u043E\u0440\u043C\u0443 \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u044B (13) (\u043C\u0430\u0442\u0435\u0440\u0438\u0438). \u042D\u0442\u043E\u0442 \u044D\u043B\u0435\u043C\u0435\u043D\u0442 \u0431\u044B\u043B \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0441\u0438\u044F \u0442\u0440\u0435\u0445 \u0441\u0432\u043E\u0439\u0441\u0442\u0432 (\u0441\u0430\u0442\u0442\u0432\u0430, \u0440\u0430\u0434\u0436\u0430\u0441 \u0438 \u0442\u0430\u043C\u0430\u0441), \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430\u043C\u0438 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u0441\u0447\u0430\u0441\u0442\u044C\u044F, \u0433\u043E\u0440\u044F \u0438 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F. \u042D\u0442\u043E \u0431\u044B\u043B\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0445 23 \u0442\u0430\u0442\u0442\u0432 \u2013 \u043E\u0442 \u0411\u0443\u0434\u0434\u0445\u0438 (\u0418\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430) \u0438\u043B\u0438 \u041C\u0430\u0445\u0430\u0442\u0430 \u0434\u043E \u041F\u0440\u0438\u0442\u0445\u0438\u0432\u0438 (\u0437\u0435\u043C\u043B\u0438). \u042D\u0442\u0438 23 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u0430 \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \xAB\u0430\u0448\u0443\u0434\u0434\u0445\u0430 \u0442\u0430\u0442\u0442\u0432\u0430\xBB (\u043D\u0435\u0447\u0438\u0441\u0442\u044B\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B).</p><p>\u042D\u0442\u0430 \u0436\u0435 \u0441\u0430\u043C\u0430\u044F \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0438\u043D\u044F\u043B\u0430 \u0444\u043E\u0440\u043C\u0443 \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u044B, \u0441\u0442\u0430\u043B\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \xAB\u044D\u0442\u043E (\u044D\u0442\u043E\u0442 \u043E\u0431\u044A\u0435\u043A\u0442) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u044D\u0442\u0438\u043C\xBB \u0438 \u043F\u0440\u0438\u043D\u044F\u043B\u0430 \u0444\u043E\u0440\u043C\u0443 \u0411\u0443\u0434\u0434\u0445\u0438-\u0442\u0430\u0442\u0442\u0432\u044B (14) (\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430), \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435 \u041C\u0430\u0445\u0430\u0442-\u0442\u0430\u0442\u0442\u0432\u044B. \u0422\u0430 \u0436\u0435 \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u0432 \u0440\u043E\u043B\u0438 \u0411\u0443\u0434\u0434\u0445\u0438-\u0442\u0430\u0442\u0442\u0432\u044B (\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430) \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u043B\u0430 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \xAB\u044F \u0438 \u043C\u043E\u0451\xBB \u0438 \u0441\u0442\u0430\u043B\u0430 \u0410\u0445\u0430\u043D\u043A\u0430\u0440\u0430-\u0442\u0430\u0442\u0442\u0432\u043E\u0439 (15) (\u044D\u0433\u043E). \u0422\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0410\u0445\u0430\u043D\u043A\u0430\u0440\u0430-\u0442\u0430\u0442\u0442\u0432\u0430 \u0441\u0442\u0430\u043B\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0438 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 \u0432\u0440\u043E\u0434\u0435 \xAB\u043A\u0430\u043C\u0435\u043D\u044C \u0438\u043B\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A\xBB \u0438 \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043B\u0430\u0441\u044C \u0432 \u041C\u0430\u043D\u0430\u0441-\u0442\u0430\u0442\u0442\u0432\u0443 (16) (\u0443\u043C). \u0411\u0443\u0434\u0434\u0445\u0438, \u0410\u0445\u0430\u043D\u043A\u0430\u0440\u0430 \u0438 \u041C\u0430\u043D\u0430\u0441 \u0432\u043C\u0435\u0441\u0442\u0435 \u043E\u0431\u0440\u0430\u0437\u0443\u044E\u0442 \u0430\u043D\u0442\u0430\u0445\u043A\u0430\u0440\u0430\u043D\u0430 (\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u043E\u0440\u0433\u0430\u043D \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0438 \u043F\u043E\u0434\u0447\u0438\u043D\u044F\u044E\u0442\u0441\u044F \u0418\u0447\u0447\u0445\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F).</p><p>\u0422\u0430 \u0436\u0435 \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430, \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u0432\u0448\u0430\u044F\u0441\u044F \u0432 \u0430\u043D\u0442\u0430\u0445\u043A\u0430\u0440\u0430\u043D\u0430, \u0441\u0442\u0430\u043B\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0437\u0432\u0443\u043A\u0430, \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u044F, \u0444\u043E\u0440\u043C\u044B, \u0432\u043A\u0443\u0441\u0430 \u0438 \u0437\u0430\u043F\u0430\u0445\u0430 \u0438 \u0440\u0430\u0437\u0432\u0438\u043B\u0430\u0441\u044C \u0432 \u0428\u0440\u043E\u0442\u0440\u0430-\u0442\u0430\u0442\u0442\u0432\u0443 (17) (\u0443\u0445\u043E), \u0422\u0432\u0430\u043A-\u0442\u0430\u0442\u0442\u0432\u0443 (18) (\u043A\u043E\u0436\u0443), \u041D\u044D\u0442\u0440\u0430-\u0442\u0430\u0442\u0442\u0432\u0443 (19) (\u0433\u043B\u0430\u0437), \u0414\u0436\u0438\u0445\u0432\u0430-\u0442\u0430\u0442\u0442\u0432\u0443 (20) (\u044F\u0437\u044B\u043A) \u0438 \u0413\u0445\u0440\u0430\u043D\u0430-\u0442\u0430\u0442\u0442\u0432\u0443 (21) (\u043D\u043E\u0441) \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E. \u042D\u0442\u043E \u043F\u044F\u0442\u044C \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0414\u0436\u043D\u044F\u043D\u0430-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0437\u043D\u0430\u043D\u0438\u044F).</p><p>\u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430, \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u0432\u0448\u0430\u044F\u0441\u044F \u0432 \u043E\u0440\u0433\u0430\u043D\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F, \u0441\u0442\u0430\u043B\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u2013 \u0440\u0435\u0447\u0438, \u0431\u0440\u0430\u043D\u0438\u044F \u0438 \u0434\u0430\u0432\u0430\u043D\u0438\u044F, \u0445\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u0432\u044B\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0441\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u0436\u0438\u0434\u043A\u043E\u0441\u0442\u0438 \u0438 \u043C\u043E\u0447\u0438. \u0422\u0430\u043A \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u043F\u0440\u0438\u043D\u044F\u043B\u0430 \u0444\u043E\u0440\u043C\u044B \u0412\u0430\u043A-\u0442\u0430\u0442\u0442\u0432\u044B (22) (\u043E\u0440\u0433\u0430\u043D\u044B \u0440\u0435\u0447\u0438), \u041F\u0430\u043D\u0438-\u0442\u0430\u0442\u0442\u0432\u044B (23) (\u0440\u0443\u043A\u0430), \u041F\u0430\u0434\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (24) (\u043D\u043E\u0433\u0430), \u041F\u0430\u0439\u044E-\u0442\u0430\u0442\u0442\u0432\u044B (25) (\u043F\u043E\u043B\u043E\u0432\u044B\u0435 \u043E\u0440\u0433\u0430\u043D\u044B) \u0438 \u0423\u043F\u0430\u0441\u0442\u0445\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (26) (\u0430\u043D\u0443\u0441). \u042D\u0442\u0438 \u043F\u044F\u0442\u044C \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u2013 \u043E\u0440\u0433\u0430\u043D\u044B \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u043C\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u041A\u0440\u0438\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F).</p><p>\u0422\u0430 \u0436\u0435 \u0441\u0430\u043C\u0430\u044F \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u043F\u0440\u0438\u043D\u044F\u043B\u0430 \u0444\u043E\u0440\u043C\u044B \u0428\u0430\u0431\u0434\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (27) (\u0437\u0432\u0443\u043A), \u0421\u043F\u0430\u0440\u0448\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (28) (\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435), \u0420\u0443\u043F\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (29) (\u0444\u043E\u0440\u043C\u0430), \u0420\u0430\u0441\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (30) (\u0432\u043A\u0443\u0441) \u0438 \u0413\u0430\u043D\u0434\u0445\u0430-\u0442\u0430\u0442\u0442\u0432\u044B (31) (\u0437\u0430\u043F\u0430\u0445), \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u043B\u0438\u0448\u044C \u0443\u0445\u043E, \u043B\u0438\u0448\u044C \u043A\u043E\u0436\u0430, \u043B\u0438\u0448\u044C \u0433\u043B\u0430\u0437\u0430, \u043B\u0438\u0448\u044C \u044F\u0437\u044B\u043A \u0438 \u043B\u0438\u0448\u044C \u043D\u043E\u0441. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0437\u0434\u0435\u0441\u044C \u043D\u0435\u0442 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F \u043D\u0430 \u0437\u0432\u0443\u043A\u0438 \u0438 \u0441\u043B\u043E\u0432\u0430, \u0445\u043E\u043B\u043E\u0434\u043D\u044B\u0435 \u0438 \u0433\u043E\u0440\u044F\u0447\u0438\u0435 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u044F, \u0441\u0438\u043D\u0438\u0435 \u0438 \u0436\u0435\u043B\u0442\u044B\u0435 \u0444\u043E\u0440\u043C\u044B, \u0441\u043B\u0430\u0434\u043A\u0438\u0435 \u0438 \u043A\u0438\u0441\u043B\u044B\u0435 \u0432\u043A\u0443\u0441\u044B, \u0430\u0440\u043E\u043C\u0430\u0442\u044B \u0438 \u0432\u043E\u043D\u044C, \u0430 \u0432\u0441\u0435 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u0442\u043E \u044D\u0442\u0438 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0422\u0430\u043D\u043C\u0430\u0442\u0440\u0430\u043C\u0438 \u0417\u0432\u0443\u043A\u0430, \u041F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u044F \u0438 \u0442.\u0434.</p><p>\u0422\u0430 \u0436\u0435 \u0428\u0430\u043A\u0442\u0438-\u0442\u0430\u0442\u0442\u0432\u0430 \u043F\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043B\u0430\u0441\u044C \u0432 \u0410\u043A\u0430\u0448\u0430-\u0442\u0430\u0442\u0442\u0432\u0443 (32) (\u043D\u0435\u0431\u043E \u0438\u043B\u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E), \u0412\u0430\u0439\u044E-\u0442\u0430\u0442\u0442\u0432\u0443 (33) (\u0432\u0435\u0442\u0435\u0440 \u0438\u043B\u0438 \u0432\u043E\u0437\u0434\u0443\u0445), \u0422\u044D\u0434\u0436\u0430\u0441-\u0442\u0430\u0442\u0442\u0432\u0443 (34) (\u043E\u0433\u043E\u043D\u044C), \u0414\u0436\u0430\u043B\u0430-\u0442\u0430\u0442\u0442\u0432\u0443 (35) (\u0432\u043E\u0434\u0430) \u0438 \u041F\u0440\u0438\u0442\u0445\u0438\u0432\u0438-\u0442\u0430\u0442\u0442\u0432\u0443 (36) (\u0437\u0435\u043C\u043B\u044F), \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043D\u044B\u0435 \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u2013 \u0437\u0432\u0443\u043A, \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u0444\u043E\u0440\u043C\u0430, \u0432\u043A\u0443\u0441 \u0438 \u0437\u0430\u043F\u0430\u0445 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E. \u042D\u0442\u043E \u043F\u044F\u0442\u044C \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432.</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, 36 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u043E\u0442 \u0428\u0438\u0432\u044B \u0434\u043E \u041F\u0440\u0438\u0442\u0445\u0438\u0432\u0438 (\u0437\u0435\u043C\u043B\u0438) \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043C\u043E\u0434\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F\u043C\u0438 \u041F\u0430\u0440\u0430\u0448\u0438\u0432\u0430-\u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 \u0438 \u043F\u0440\u0438\u0441\u0443\u0449\u0435\u0439 \u0435\u043C\u0443 \u0428\u0430\u043A\u0442\u0438 (\u0441\u0438\u043B\u044B).</p></div><p><i>\u0418\u0437 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0435\u0432 \u041C. \u0428\u0438\u0432\u0430\u043A\u0443\u043C\u0430\u0440\u0430 \u0421\u0432\u0430\u043C\u0438 \u043A <strong>\u0428\u0440\u0438 \u0421\u0438\u0434\u0434\u0445\u0430\u043D\u0442\u0430 \u0428\u0438\u043A\u0445\u0430\u043C\u0430\u043D\u0438</strong> . \u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u2013 <strong>\u042E\u043B\u0438\u044F \u041A\u0440\u0430\u0432\u0447\u0435\u043D\u043A\u043E (\u0413\u0430\u0443\u0440\u0438)</strong> . \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A: <a href="http://www.vaikuntha.ru/blog/veerashaiva/1506.html" target="_blank">http://www.vaikuntha.ru/blog/veerashaiva/1506.html</a></i></p>',2),r=[s];function n(_,c,i,l,d,h){return e(),t("div",null,r)}var v=p(o,[["render",n]]);export{u as __pageData,v as default};
